db.insert(taskEventsTable).values({ id: "evt-1", taskId: "task-1", type: "created", createdAt: new Date().toISOString() }).run();

// Verify data exists
let eventCount = db.select().from(taskEventsTable).all().length;
console.log("Before migration:", eventCount); // Should be 1

// Run migration 0005
runMigrations();

// Check if task_events was wiped
eventCount = db.select().from(taskEventsTable).all().length;
console.log("After migration:", eventCount); // BUG: 0 (should be 1)
```

**After the fix:**
```ts
