# Fix

```ts
// streaming/sse-server.ts
import * as http from "http";
import { logger } from "./logger"; // adjust import as needed
import type { TaskStore } from "./task-store"; // adjust import as needed

export interface SseServerOptions {
  port?: number;
  host?: string;
}

export function startSseServer(
  taskStore: TaskStore,
  options: SseServerOptions = {}
): http.Server {
  const port = options.port ?? parseInt(process.env["SSE_PORT"] ?? "3001", 10);
  const host = options.host ?? process.env["SSE_HOST"] ?? "127.0.0.1";

  const server = http.createServer((req, res) => {
    /* ...SSE routing... */
  });

  // Handle binding errors gracefully
  server.on("error", (err: NodeJS.ErrnoException) => {
    if (err.code === "EADDRINUSE") {
      logger.warn(
        { host, port, error: err.message },
        "SSE server failed to bind: port already in use. SSE will be unavailable."
      );
    } else {
      logger.error(
        { host, port, error: err.message, code: err.code },
        "SSE server error"
      );
    }
    // Do NOT rethrow or crash. The MCP server continues running.
  });

  server.listen(port, host, () => {
    logger.info({ host, port }, "SSE server listening");
  });

  return server;
}
```

**Changes:**
1. Added `SseServerOptions` interface with optional `port` and `host`.
2. `startSseServer()` now accepts `options` parameter; falls back to env vars, then defaults.
3. Attached an `'error'` event listener that:
   - Logs `EADDRINUSE` as a warning (expected failure mode).
   - Logs other errors as errors (unexpected).
   - Does **not** rethrow or crash.
4. The MCP server in `index.ts` continues running; SSE is simply unavailable.

**Update index.ts (optional, for clarity):**
